{
  "name": "Meals on Wheels of Rhode Island",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits or dollar amounts mentioned; eligibility not based on income. Some clients receive meals through grant and donor funding, with private pay option for others.[1][5]",
    "asset_limits": "No asset limits mentioned or applicable.[1][5]",
    "other_requirements": ["Homebound (unable to safely leave the home on their own)", "Not participating in an adult daycare or dining program on scheduled meal delivery days", "For state Waiver program qualifiers under age 60 (details not specified)", "For Capital City Café: 60+ or under 60 with disability or receiving general public assistance"][1]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious, fully-prepared meals meeting one-third of daily dietary intake, delivered each weekday to approximately 1,500 seniors statewide (including Block Island); includes daily well-being check and friendly visit to reduce isolation. Capital City Café program (congregate dining, separate eligibility). Private pay available for non-eligible or immediate needs.[1][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online or download referral form from www.rimeals.org and mail to Meals on Wheels of RI, Inc., 70 Bath St., Providence, RI 02908 (Home-Delivered Meal Program)", "Online or download enrollment form from www.rimeals.org (Capital City Café Program)", "Phone: (401) 351-6700 (contact Shana DeFelice, Programs & Mission Impact Director)", "Email: sdefelice@rimeals.org"],
    "processing_time": "Eligibility confirmed by home-delivered team upon receiving form; specific timelines not stated, but enrollment follows confirmation.[1]",
    "waitlist": "Not mentioned; private pay offered for immediate needs.[1][5]",
    "forms": ["Referral form (Home-Delivered Meal Program)", "Enrollment form (Capital City Café Program)"],
    "documents": "Not explicitly listed; general proof of age, homebound status, or disability may be assessed during eligibility confirmation (no income proof required).[1][2]"
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves all of Rhode Island, including Block Island.[5]",
    "regional_variations": "Uniform statewide operation as the only nonprofit home-delivered meal program of its kind; no regional differences in eligibility, benefits, or wait times noted.[1][5]",
    "offices_or_providers": ["Meals on Wheels of RI, Inc., 70 Bath St., Providence, RI 02908"]
  },
  "official_source": "www.rimeals.org",
  "gotchas": ["Must not be in adult daycare/dining on delivery days", "Separate eligibility for Capital City Café (congregate, not home-delivered)", "Private pay required if not meeting eligibility or for immediate access", "No mention of income/assets, but funding via grants/donors may prioritize certain clients", "Homebound defined strictly as unable to safely leave home independently[1][5]"],
  "data_shape_notes": "No income or asset tests; eligibility focused on age, homebound status, and program non-participation; statewide with private pay option; two programs (home-delivered and café) with distinct forms/eligibility."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a long-term care facility such as nursing home, assisted living, hospice, or licensed home care; or receiving services at Bristol Veterans Home, Eleanor Slater Hospital Regan Building in Cranston, or Zambarano Hospital in Pascoag; open to older persons and people with disabilities receiving long-term care services."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to resolve complaints via mediation, negotiation, and administrative action; investigation of abuse, neglect, mistreatment, financial exploitation; education on residents' rights; support for resident and family councils; facility inspections; representation before agencies; assistance with issues like improper discharge, food quality, medication, and care quality; no financial aid, hours, or dollar amounts provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (401) 785-3340 or toll-free 1-888-351-0808", "Online contact form: https://alliancebltc.org/ombudsman-program/contact/", "Mail: Office of Healthy Aging, 25 Howard Ave, Building 57, Cranston, RI 02920"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["No specific forms mentioned; contact via phone or online form to report concerns or seek assistance."],
    "documents": ["No documents required; families can contact directly to discuss concerns on behalf of residents."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to individuals in specific long-term care settings across Rhode Island (nursing homes, assisted living, licensed home care, hospice, named facilities).",
    "regional_variations": null,
    "offices_or_providers": ["Office of the RI State Long Term Care Ombudsman, housed within the Alliance for Better Long Term Care, 422 Post Road, Suite 204, Warwick, RI 02888."]
  },
  "official_source": "https://alliancebltc.org/ombudsman-program/overview/",
  "gotchas": ["Not a direct service provider or financial assistance program—focuses solely on advocacy and complaint resolution; only for those already in long-term care facilities or specific services, not for placement or pre-admission help; anyone (resident, family, staff, agency) can file complaints on behalf of residents; operates independently but funded by federal Older Americans Act, state grants, and donations."],
  "data_shape_notes": "no income test; advocacy-only with no financial benefits or waitlists; restricted to residents of defined long-term care settings statewide; contact-based rather than formal application."
}

{
  "name": "At Home Cost Share Program",
  "eligibility": {
    "age": "65 or older, or 19-64 with a diagnosis of Alzheimer’s or a related dementia",
    "income_limits": "Capped at 250% of the Federal Poverty Level (FPL). Specific tiers from 2024 factsheet: Tier 1 - $18,825 (single), $25,550 (couple); Tier 2 - $30,120 (single), $40,880 (couple). Limits vary by household size and are adjusted annually; contact OHA for current FPL-based table[1][5][6].",
    "asset_limits": "No asset limit[1][4][5].",
    "other_requirements": [
      "Needs assessment to determine eligibility for in-home or community-based services",
      "Do not qualify for Rhode Island’s Medicaid program[4][5]",
      "Need assistance at home with personal or health care, housekeeping, personal care, or meal preparation[1][4][5]"
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "State shares cost of in-home services (e.g., housekeeping, personal care, meal preparation) and/or community adult-day programs (personal care, nursing, meals, recreational/social activities). Participant pays sliding scale co-pay based on income: e.g., Tier 1 - $4.50/hour home care, $7.00/day adult day; Tier 2 - $7.50/hour home care, $15.00/day adult day (2024 rates; private pay averages $25-27/hour home care, $90-100/day adult day). Individualized assessment and care plan provided[1][4][5].",
    "varies_by": "income_tier"
  },
  "application": {
    "methods": [
      "Phone: Contact ADRC/POINT at 401-462-4444[1][4]",
      "No specific online URL, mail, or in-person details listed; start via phone for assessment"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": "Not specified in sources",
    "forms": ["No specific form names/numbers provided; process begins with phone contact and needs assessment[1]"],
    "documents": ["Proof of income (to determine tier and co-pay), documentation of Alzheimer's/dementia if age 19-64, needs assessment completed during application[1][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None specified",
    "regional_variations": "No regional differences, providers, or wait times detailed; statewide via OHA[1]",
    "offices_or_providers": ["Administered statewide by Office of Healthy Aging (OHA); contact via ADRC/POINT[1][4]"]
  },
  "official_source": "https://oha.ri.gov/resources/home-care/home-cost-share",
  "gotchas": [
    "Not Medicaid (RIte@Home); separate program for non-Medicaid eligible with needs assessment required[1][4][5]",
    "Income tiers determine co-pay amounts, not full coverage; participants pay share (e.g., $4.50-$15/day)[5]",
    "Eligibility expanded in recent years to 250% FPL and younger adults with dementia—check current limits as FPL adjusts annually[1][6]",
    "Distinct from Medicaid programs with asset tests or NFLOC requirements[2]",
    "Private pay costs much higher, so program subsidizes but does not eliminate participant costs[4][5]"
  ],
  "data_shape_notes": "Income-based sliding scale co-pays with tiers (no asset test); benefits via state subsidy on services, not fixed hours/dollars; FPL-based limits adjust yearly; needs assessment mandatory"
}

{
  "name": "Senior Companion Program",
  "eligibility": {
    "age": 55,
    "income_limits": "Income must meet AmeriCorps guidelines to receive stipend (specific dollar amounts not listed in RI sources; reviewed annually; low-income required for stipend eligibility)[1][6]",
    "asset_limits": "No asset limits specified in RI sources",
    "other_requirements": ["Physical exam certifying ability to volunteer without detriment to self or clients[1]", "Pass criminal history and background checks[1]", "For volunteers: capable of providing companionship and assistance with daily tasks[6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Companionship for frail older adults in home, day centers, or community sites; assistance with daily tasks (e.g., transportation to medical appointments, shopping assistance, meal preparation, advocacy); respite for caregivers; volunteers (age 55+) receive training, supervision, annual recognition, and if income-eligible: tax-free stipend, travel/meal reimbursements (does not affect SSI/SSDI, etc.)[1][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 401-462-0569 (Rhode Island Senior Companion Program)[6]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": [],
    "documents": ["For volunteers: documentation of physical exam, proof of income for stipend, background check materials[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": ["Office of Healthy Aging (RI.gov), phone 401-462-0569[6]"]
  },
  "official_source": "https://oha.ri.gov/get-involved/volunteering/senior-companions[6]",
  "gotchas": ["Program recruits volunteers (seniors 55+) to serve frail elders, not direct financial aid to recipients; stipend and benefits are for volunteers, not clients; clients receive non-medical companionship/services only; income eligibility applies only for volunteer stipends, not clients[1][6]", "No specific RI income tables or client eligibility details provided; contact program for current AmeriCorps guidelines[1][6]"],
  "data_shape_notes": "Volunteer-based AmeriCorps program pairing senior volunteers with frail elders; limited RI-specific details on income/assets; statewide via Office of Healthy Aging[6]"
}
